// Lightweight Markdown parser for MD Notes extension
// Supports: headings, bold, italic, code, lists, links, tables, blockquotes, hr, code blocks

(function(global) {
  function escapeHtml(str) {
    return str
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;');
  }

  function parseInline(text) {
    // Code spans first (protect from other parsing)
    const codeSpans = [];
    text = text.replace(/`([^`]+)`/g, (_, code) => {
      const i = codeSpans.length;
      codeSpans.push(`<code>${escapeHtml(code)}</code>`);
      return `\x00CODE${i}\x00`;
    });

    // Bold + italic: ***text***
    text = text.replace(/\*\*\*(.+?)\*\*\*/g, '<strong><em>$1</em></strong>');
    // Bold: **text** or __text__
    text = text.replace(/\*\*(.+?)\*\*/g, '<strong>$1</strong>');
    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');
    // Italic: *text* or _text_
    text = text.replace(/\*([^*]+)\*/g, '<em>$1</em>');
    text = text.replace(/_([^_]+)_/g, '<em>$1</em>');
    // Strikethrough: ~~text~~
    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');
    // Links: [text](url) and [text](url "title")
    text = text.replace(/\[([^\]]+)\]\(([^)]+?)(?:\s+"[^"]*")?\)/g, (_, t, url) => {
      return `<a href="${escapeHtml(url)}" target="_blank" rel="noopener">${t}</a>`;
    });
    // Auto links
    text = text.replace(/\bhttps?:\/\/[^\s<>"]+/g, url => {
      return `<a href="${escapeHtml(url)}" target="_blank" rel="noopener">${escapeHtml(url)}</a>`;
    });

    // Restore code spans
    text = text.replace(/\x00CODE(\d+)\x00/g, (_, i) => codeSpans[parseInt(i)]);
    return text;
  }

  function parseTable(lines) {
    const rows = lines.map(l => l.replace(/^\||\|$/g, '').split('|').map(c => c.trim()));
    const header = rows[0];
    // row[1] is separator
    const body = rows.slice(2);
    let html = '<table><thead><tr>';
    header.forEach(cell => html += `<th>${parseInline(cell)}</th>`);
    html += '</tr></thead><tbody>';
    body.forEach(row => {
      html += '<tr>';
      row.forEach((cell, i) => {
        if (i < header.length) html += `<td>${parseInline(cell)}</td>`;
      });
      // Fill missing cells
      for (let i = row.length; i < header.length; i++) html += '<td></td>';
      html += '</tr>';
    });
    html += '</tbody></table>';
    return html;
  }

  function isTableSep(line) {
    return /^\|?[\s\-:|]+\|[\s\-:|]*$/.test(line);
  }

  function parse(md) {
    const lines = md.split('\n');
    let html = '';
    let i = 0;

    while (i < lines.length) {
      const line = lines[i];

      // Fenced code block
      if (/^```/.test(line)) {
        const lang = line.slice(3).trim();
        let code = '';
        i++;
        while (i < lines.length && !/^```/.test(lines[i])) {
          code += lines[i] + '\n';
          i++;
        }
        i++; // skip closing ```
        const langAttr = lang ? ` class="language-${escapeHtml(lang)}"` : '';
        html += `<pre><code${langAttr}>${escapeHtml(code.replace(/\n$/, ''))}</code></pre>\n`;
        continue;
      }

      // Headings
      const hMatch = line.match(/^(#{1,6})\s+(.*)/);
      if (hMatch) {
        const level = hMatch[1].length;
        html += `<h${level}>${parseInline(hMatch[2])}</h${level}>\n`;
        i++;
        continue;
      }

      // Horizontal rule
      if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
        html += '<hr>\n';
        i++;
        continue;
      }

      // Blockquote
      if (/^>\s?/.test(line)) {
        let blockContent = '';
        while (i < lines.length && /^>\s?/.test(lines[i])) {
          blockContent += lines[i].replace(/^>\s?/, '') + '\n';
          i++;
        }
        html += `<blockquote>${parse(blockContent.trim())}</blockquote>\n`;
        continue;
      }

      // Table detection
      if (i + 1 < lines.length && isTableSep(lines[i + 1]) && /\|/.test(line)) {
        const tableLines = [line];
        i++;
        tableLines.push(lines[i]); // sep
        i++;
        while (i < lines.length && /\|/.test(lines[i]) && lines[i].trim() !== '') {
          tableLines.push(lines[i]);
          i++;
        }
        html += parseTable(tableLines) + '\n';
        continue;
      }

      // Unordered list
      if (/^(\s*)([-*+])\s+/.test(line)) {
        let items = '';
        while (i < lines.length && /^(\s*)([-*+])\s+/.test(lines[i])) {
          const text = lines[i].replace(/^\s*[-*+]\s+/, '');
          items += `<li>${parseInline(text)}</li>\n`;
          i++;
        }
        html += `<ul>\n${items}</ul>\n`;
        continue;
      }

      // Ordered list
      if (/^\d+\.\s+/.test(line)) {
        let items = '';
        while (i < lines.length && /^\d+\.\s+/.test(lines[i])) {
          const text = lines[i].replace(/^\d+\.\s+/, '');
          items += `<li>${parseInline(text)}</li>\n`;
          i++;
        }
        html += `<ol>\n${items}</ol>\n`;
        continue;
      }

      // Blank line
      if (line.trim() === '') {
        i++;
        continue;
      }

      // Paragraph â€” collect consecutive non-special lines
      let paraLines = [];
      while (
        i < lines.length &&
        lines[i].trim() !== '' &&
        !/^#{1,6}\s/.test(lines[i]) &&
        !/^```/.test(lines[i]) &&
        !/^>\s?/.test(lines[i]) &&
        !/^(\s*)([-*+])\s+/.test(lines[i]) &&
        !/^\d+\.\s+/.test(lines[i]) &&
        !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i]) &&
        !(paraLines.length === 0 && i + 1 < lines.length && isTableSep(lines[i + 1]) && /\|/.test(lines[i]))
      ) {
        paraLines.push(lines[i]);
        i++;
      }
      if (paraLines.length > 0) {
        html += `<p>${parseInline(paraLines.join(' '))}</p>\n`;
      }
    }

    return html;
  }

  // Expose as global marked with .parse() method to match marked.js API
  global.marked = { parse };
})(window);

